import { useRef, useState } from 'react';
import { Header } from './components/Header';
import { InputsPanel } from './components/InputsPanel';
import { ScenarioOverview } from './components/tabs/ScenarioOverview';
import { PhilanthropicProjection } from './components/tabs/PhilanthropicProjection';
import { TierForecast } from './components/tabs/TierForecast';
import { DEFAULT_INPUTS } from './lib/model';
import type { FinancialInputs } from './lib/model';

// Endowment Runway + Sensitivity Tornado tabs archived 2026-05-13 — see _archive/README.md.
// Monte Carlo Stress Test archived 2026-05-13 (S73, post-audit) — see _archive/README.md.
// The deterministic Pessimistic scenario on Scenario Overview does the stress-test work.

type TabKey = 'tierForecast' | 'scenarios' | 'philanthropic';

const TABS: { key: TabKey; label: string; sub: string }[] = [
  { key: 'scenarios', label: 'Scenario Overview', sub: 'Multi-year endowment model' },
  { key: 'tierForecast', label: 'FY27 Pipeline', sub: 'Floor · Base · Stretch — live from workbook' },
  { key: 'philanthropic', label: 'Philanthropic Revenue', sub: 'Committed · Likely · Gap' },
];

export default function App() {
  const [inputs, setInputs] = useState<FinancialInputs>(DEFAULT_INPUTS);
  const [tab, setTab] = useState<TabKey>('scenarios');
  const tabRefs = useRef<Array<HTMLButtonElement | null>>([]);

  const showInputsPanel = tab !== 'tierForecast';

  const today = new Date().toLocaleDateString('en-US', {
    year: 'numeric',
    month: 'long',
    day: 'numeric',
  });

  const handleTabKeyDown = (
    e: React.KeyboardEvent<HTMLButtonElement>,
    idx: number
  ) => {
    let nextIdx: number | null = null;
    if (e.key === 'ArrowRight') nextIdx = (idx + 1) % TABS.length;
    else if (e.key === 'ArrowLeft') nextIdx = (idx - 1 + TABS.length) % TABS.length;
    else if (e.key === 'Home') nextIdx = 0;
    else if (e.key === 'End') nextIdx = TABS.length - 1;
    if (nextIdx === null) return;
    e.preventDefault();
    setTab(TABS[nextIdx].key);
    tabRefs.current[nextIdx]?.focus();
  };

  return (
    <div className="min-h-screen flex flex-col">
      <a
        href="#main-content"
        className="sr-only focus:not-sr-only focus:fixed focus:top-2 focus:left-2 focus:z-50 focus:bg-purple focus:text-white focus:px-4 focus:py-2 focus:rounded focus:font-head focus:uppercase focus:tracking-wide-15 focus:text-sm focus:shadow-lg"
      >
        Skip to main content
      </a>

      <Header asOf={today} />

      <nav className="bg-white border-b border-navy/10 no-print" aria-label="Primary">
        <div className="max-w-screen-2xl mx-auto px-6">
          <div
            role="tablist"
            aria-label="Financial model views"
            className="flex gap-1 overflow-x-auto -mb-px"
          >
            {TABS.map((t, i) => {
              const isActive = tab === t.key;
              return (
                <button
                  key={t.key}
                  ref={(el) => {
                    tabRefs.current[i] = el;
                  }}
                  role="tab"
                  aria-selected={isActive}
                  aria-controls={`panel-${t.key}`}
                  id={`tab-${t.key}`}
                  tabIndex={isActive ? 0 : -1}
                  onClick={() => setTab(t.key)}
                  onKeyDown={(e) => handleTabKeyDown(e, i)}
                  className={`px-4 py-3 text-left border-b-2 transition-colors whitespace-nowrap focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-purple/60 focus-visible:ring-inset ${
                    isActive
                      ? 'border-purple text-navy'
                      : 'border-transparent text-navy/70 hover:text-navy hover:border-navy/30'
                  }`}
                >
                  <div className="font-head uppercase tracking-wide-15 text-sm">{t.label}</div>
                  <div className="text-xs text-navy/65 font-sub mt-0.5">{t.sub}</div>
                </button>
              );
            })}
          </div>
        </div>
      </nav>

      <main id="main-content" tabIndex={-1} className="flex-1 bg-tan/40">
        <div
          className={`max-w-screen-2xl mx-auto px-6 py-6 grid grid-cols-1 gap-6 ${
            showInputsPanel ? 'lg:grid-cols-[20rem_1fr]' : ''
          }`}
        >
          {showInputsPanel && <InputsPanel inputs={inputs} setInputs={setInputs} />}
          <div
            role="tabpanel"
            id={`panel-${tab}`}
            aria-labelledby={`tab-${tab}`}
          >
            {tab === 'tierForecast' && <TierForecast inputs={inputs} />}
            {tab === 'scenarios' && <ScenarioOverview inputs={inputs} />}
            {tab === 'philanthropic' && (
              <PhilanthropicProjection inputs={inputs} setInputs={setInputs} />
            )}
          </div>
        </div>
      </main>

      <footer className="bg-navy text-white/70 text-xs no-print">
        <div className="max-w-screen-2xl mx-auto px-6 py-4 flex items-center justify-between flex-wrap gap-2">
          <div>DC CAP Innovation Hub · FY27 Revenue Pipeline · viewed {today}</div>
          <div className="font-head uppercase tracking-wide-15 text-purple-100">
            Excel Beyond Belief
          </div>
        </div>
      </footer>
    </div>
  );
}
