function ProspectRow({ row }: { row: PipelineRow }) {
  // Use the tier color for the swatch dot only; tier label text stays navy so
  // T2 (brand blue) and T4 (slate) labels meet WCAG AA on white backgrounds.
  const tierColor = TIER_DEFINITIONS[row.tier].color;
  const unsized = row.aorAmount === 0;
  return (
    <tr className="border-b border-navy/5 hover:bg-tan/40">
      <td className="text-left py-2 pr-3 font-sub">
        {row.funder}
        {row.constituentId && (
          <span className="ml-2 text-xs text-navy/65">#{row.constituentId}</span>
        )}
      </td>
      <td className="text-left px-3 py-2 font-sub text-xs text-navy/70">{row.segment}</td>
      <td className="text-left px-3 py-2">
        <span className="inline-flex items-center gap-1.5 text-xs font-head text-navy">
          <span
            className="inline-block w-2 h-2 rounded-sm"
            style={{ background: tierColor }}
          />
          T{row.tier}
        </span>
      </td>
      <td className="text-right px-3 py-2 font-semibold">
        {unsized ? (
          <span
            className="text-navy/65 font-sub"
            title="Cultivation prospect — ask amount not yet sized"
          >
            —
          </span>
        ) : (
          dollars(row.aorAmount, { compact: true })
        )}
      </td>
      <td className="text-right px-3 py-2 font-sub text-navy/70">
        {row.restrictedAddOn > 0 ? dollars(row.restrictedAddOn, { compact: true }) : ''}
      </td>
      <td className="text-left px-3 py-2 font-sub text-xs text-navy/70">{row.owner || '—'}</td>
      <td className="text-left px-3 py-2 font-sub text-sm text-navy/70 max-w-md">
        {row.notes}
      </td>
      <td
        className="text-left px-3 py-2 font-sub text-xs text-navy/65"
        title={`Source: ${row._source.tab} tab, row ${row._source.rowIndex}`}
      >
        {row._source.tab[0]}#{row._source.rowIndex}
      </td>
    </tr>
  );
}

interface ScenarioCardProps {
  label: string;
  subtitle: string;
  /** Scenario total (Pre-Booked + tier rollups under cutoff method). */
  total: number;
  /** Org-level Total AOR Goal — primary denominator ($5.82M in May 2026 workbook). */
  totalAorGoal: number;
  /** Eric's manual total-org ambition target — tertiary anchor only. */
  ambitionTarget: number;
  color: string;
  accent: string;
  countLabel: string;
  /** Restricted dollars riding alongside this scenario (Floor: Tier-1 restricted add-ons). */
  restrictedAddOn?: number;
  large?: boolean;
}

function ScenarioCard({
  label,
  subtitle,
  total,
  totalAorGoal,
  ambitionTarget,
  color,
  accent,
  countLabel,
  restrictedAddOn,
  large,
}: ScenarioCardProps) {
  const totalCoverage = totalAorGoal > 0 ? total / totalAorGoal : 0;
  const ambCoverage = ambitionTarget > 0 ? total / ambitionTarget : 0;
  return (
    <div className="card" style={{ borderTop: `4px solid ${color}` }}>
      <div className="card-body">
        <div className="font-head uppercase tracking-wide-15 text-sm text-navy/70">{label}</div>
        <div className="text-sm text-navy/65 font-sub mt-1">{subtitle}</div>
        <div className={`font-head text-navy mt-2 ${large ? 'text-4xl' : 'text-3xl'}`}>
          {dollars(total, { compact: true })}
        </div>
        {restrictedAddOn !== undefined && restrictedAddOn > 0 && (
          <div className="mt-1.5 inline-flex items-center gap-1.5 text-xs font-sub px-2 py-0.5 rounded bg-purple/10 text-purple-900">
            <span className="font-head uppercase tracking-wide-15 text-[10px]">+ Restricted</span>
            <span className="num font-semibold">
              {dollars(restrictedAddOn, { compact: true })}
            </span>
          </div>
        )}
        <div className="text-sm text-navy/75 font-sub mt-2">
          {totalAorGoal > 0 ? (
            <span>
              <strong className="num">{percent(totalCoverage, 0)}</strong> of total AOR goal{' '}
              <span className="text-navy/65 num">
                ({dollars(totalAorGoal, { compact: true })})
              </span>
            </span>
          ) : (
            'Total AOR goal not set'
          )}
        </div>
        {ambitionTarget > 0 && (
          <div className="text-xs text-navy/55 font-sub mt-1">
            <span className="num">{percent(ambCoverage, 0)}</span> of total-org ambition target
            <span className="text-navy/55"> ({dollars(ambitionTarget, { compact: true })})</span>
          </div>
        )}
        <div className="text-xs text-navy/65 font-sub mt-3 leading-snug">{countLabel}</div>
        <p className="text-sm text-navy/65 font-sub mt-2 italic">{accent}</p>
      </div>
    </div>
  );
}

