/**
 * Horizontal stack bar showing how Pre-Booked AOR + Tier 1 (= Floor) builds to
 * + Tier 2 (= Base) and + Tier 3 (= Stretch). Markers at each cutoff so IC
 * readers see the layering and the segment-goal anchor in one view.
 */
function CumulativeStackBar({
  preBooked,
  tier1,
  tier2,
  tier3,
  totalAorGoal,
}: {
  preBooked: number;
  tier1: number;
  tier2: number;
  tier3: number;
  /** Org-level Total AOR Goal (Pre-Booked + New) — the goal anchor on the bar. */
  totalAorGoal: number;
}) {
  const stretch = preBooked + tier1 + tier2 + tier3;
  const floor = preBooked + tier1;
  const base = floor + tier2;
  // Scale axis to whichever is larger: Stretch or the total AOR goal — so the
  // goal marker is always inside the bar.
  const max = Math.max(stretch, totalAorGoal) * 1.05;
  const pct = (n: number) => (max > 0 ? `${(n / max) * 100}%` : '0%');
  return (
    <section className="card">
      <div className="card-header flex items-baseline justify-between flex-wrap gap-2">
        <div>
          <div className="eyebrow">How the scenarios stack</div>
          <h2 className="font-head text-base">Floor → Base → Stretch composition</h2>
        </div>
        <div className="text-xs text-navy/65 font-sub">
          Goal anchor: {dollars(totalAorGoal, { compact: true })} total AOR target
        </div>
      </div>
      <div className="card-body">
        <div
          className="relative h-12 w-full bg-tan/40 rounded overflow-hidden border border-navy/10"
          role="img"
          aria-label={`Pipeline composition: Pre-Booked ${dollars(preBooked, { compact: true })}, Tier 1 ${dollars(tier1, { compact: true })}, Tier 2 ${dollars(tier2, { compact: true })}, Tier 3 ${dollars(tier3, { compact: true })}, total AOR goal ${dollars(totalAorGoal, { compact: true })}`}
        >
          {/* Stack segments */}
          <div className="absolute inset-y-0 left-0 flex" style={{ width: pct(stretch) }}>
            <div
              className="h-full"
              style={{ width: `${(preBooked / stretch) * 100}%`, background: '#0a1136' }}
              title={`Pre-Booked AOR · ${dollars(preBooked, { compact: true })}`}
            />
            <div
              className="h-full"
              style={{ width: `${(tier1 / stretch) * 100}%`, background: NAVY, opacity: 0.85 }}
              title={`Tier 1 · ${dollars(tier1, { compact: true })}`}
            />
            <div
              className="h-full"
              style={{ width: `${(tier2 / stretch) * 100}%`, background: BRAND_BLUE }}
              title={`Tier 2 · ${dollars(tier2, { compact: true })}`}
            />
            <div
              className="h-full"
              style={{ width: `${(tier3 / stretch) * 100}%`, background: PURPLE }}
              title={`Tier 3 · ${dollars(tier3, { compact: true })}`}
            />
          </div>
          {/* Cutoff markers */}
          <div
            className="absolute top-0 bottom-0 border-r-2 border-white/80"
            style={{ left: pct(floor) }}
            aria-hidden
          />
          <div
            className="absolute top-0 bottom-0 border-r-2 border-white/80"
            style={{ left: pct(base) }}
            aria-hidden
          />
          {/* Total AOR goal marker */}
          <div
            className="absolute top-0 bottom-0 border-l-2 border-dashed border-amber-500"
            style={{ left: pct(totalAorGoal) }}
            aria-hidden
            title={`Total AOR goal · ${dollars(totalAorGoal, { compact: true })}`}
          />
        </div>
        {/* Cutoff labels — absolute-positioned at md+, fall back to a simple
            row at narrow widths where the cutoffs would otherwise collide. */}
        <div className="hidden md:block relative w-full mt-2 h-10 text-xs font-sub">
          <CutoffLabel left={pct(floor)} label="Floor" amount={floor} color={NAVY} />
          <CutoffLabel left={pct(base)} label="Base" amount={base} color={BRAND_BLUE} />
          <CutoffLabel left={pct(stretch)} label="Stretch" amount={stretch} color={PURPLE} />
          <CutoffLabel
            left={pct(totalAorGoal)}
            label="Goal"
            amount={totalAorGoal}
            color="#b45309"
            dashed
          />
        </div>
        <div className="md:hidden grid grid-cols-2 gap-x-3 gap-y-1.5 mt-3 text-xs font-sub">
          <MobileCutoff label="Floor" amount={floor} color={NAVY} />
          <MobileCutoff label="Base" amount={base} color={BRAND_BLUE} />
          <MobileCutoff label="Stretch" amount={stretch} color={PURPLE} />
          <MobileCutoff label="Goal" amount={totalAorGoal} color="#b45309" dashed />
        </div>
        <div className="flex flex-wrap gap-x-4 gap-y-1 text-xs text-navy/70 font-sub mt-3">
          <SwatchLabel color="#0a1136" label="Pre-Booked AOR (committed)" />
          <SwatchLabel color={NAVY} label="Tier 1 (very likely)" opacity={0.85} />
          <SwatchLabel color={BRAND_BLUE} label="Tier 2 (somewhat likely)" />
          <SwatchLabel color={PURPLE} label="Tier 3 (possible)" />
        </div>
      </div>
    </section>
  );
}

function CutoffLabel({
  left,
  label,
  amount,
  color,
  dashed,
}: {
  left: string;
  label: string;
  amount: number;
  color: string;
  dashed?: boolean;
}) {
  return (
    <div
      className="absolute -translate-x-1/2 text-center whitespace-nowrap"
      style={{ left }}
    >
      <div
        className={`font-head text-xs uppercase tracking-wide-15 ${dashed ? 'italic' : ''}`}
        style={{ color }}
      >
        {label}
      </div>
      <div className="num text-navy/75 text-xs">{dollars(amount, { compact: true })}</div>
    </div>
  );
}

function SwatchLabel({
  color,
  label,
  opacity = 1,
}: {
  color: string;
  label: string;
  opacity?: number;
}) {
  return (
    <span className="inline-flex items-center gap-1.5">
      <span
        className="inline-block w-3 h-3 rounded-sm"
        style={{ background: color, opacity }}
      />
      {label}
    </span>
  );
}

function MobileCutoff({
  label,
  amount,
  color,
  dashed,
}: {
  label: string;
  amount: number;
  color: string;
  dashed?: boolean;
}) {
  return (
    <div className="flex items-baseline justify-between gap-2 border-b border-navy/5 pb-1">
      <span
        className={`font-head text-xs uppercase tracking-wide-15 ${dashed ? 'italic' : ''}`}
        style={{ color }}
      >
        {label}
      </span>
      <span className="num text-navy font-semibold">
        {dollars(amount, { compact: true })}
      </span>
    </div>
  );
}

function SensitivityCell({
  label,
  sublabel,
  value,
  vsCutoff,
  cutoffLabel,
  cutoffValue,
  color,
  accent,
}: {
  label: string;
  sublabel: string;
  value: number;
  vsCutoff: number;
  cutoffLabel: string;
  cutoffValue: number;
  color: string;
  accent?: boolean;
}) {
  const sign = vsCutoff >= 0 ? '+' : '−';
  const deltaColor = vsCutoff >= 0 ? 'text-emerald-700' : 'text-rose-700';
  return (
    <div
      className={`rounded border p-3 ${
        accent ? 'bg-tan/40 border-navy/25' : 'bg-tan/20 border-navy/15'
      }`}
      style={{ borderTop: `3px solid ${color}` }}
    >
      <div className="font-head text-xs uppercase tracking-wide-15 text-navy/70">
        {label}
      </div>
      <div className="text-[10px] font-sub text-navy/65 mt-0.5">{sublabel}</div>
      <div className="font-head text-2xl mt-1.5 text-navy">
        {dollars(value, { compact: true })}
      </div>
      <div className={`text-xs font-sub mt-1 ${deltaColor}`}>
        {sign} {dollars(Math.abs(vsCutoff), { compact: true })} vs. cutoff{' '}
        <span className="text-navy/65">
          {cutoffLabel} ({dollars(cutoffValue, { compact: true })})
        </span>
      </div>
    </div>
  );
}

/** Per-segment cell showing weighted dollars + delta vs. cutoff. */
function SegCell({ weighted, cutoff }: { weighted: number; cutoff: number }) {
  const delta = weighted - cutoff;
  const deltaColor = delta >= 0 ? 'text-emerald-700' : 'text-rose-700';
  const sign = delta >= 0 ? '+' : '−';
  return (
    <td className="text-right px-3 py-2">
      <div className="text-navy font-semibold">{dollars(weighted, { compact: true })}</div>
      <div className={`text-xs ${deltaColor}`}>
        {sign} {dollars(Math.abs(delta), { compact: true })}
      </div>
    </td>
  );
}

function ApplyMatrixGrid({ rates }: { rates: CloseRateMatrix }) {
  return (
    <div className="overflow-x-auto">
      <table className="w-full text-xs num">
        <thead>
          <tr className="text-navy/65 uppercase tracking-wider">
            <th className="text-left py-1.5 pr-3 font-head">Segment</th>
            <th className="text-right px-2 py-1.5 font-head">T1</th>
            <th className="text-right px-2 py-1.5 font-head">T2</th>
            <th className="text-right px-2 py-1.5 font-head">T3</th>
            <th className="text-right px-2 py-1.5 font-head">T4</th>
          </tr>
        </thead>
        <tbody>
          {SEGMENTS.map((seg) => (
            <tr key={seg} className="border-t border-navy/5">
              <td className="text-left py-1.5 pr-3 font-head text-navy/70">{seg}</td>
              {([1, 2, 3, 4] as TierLevel[]).map((t) => (
                <td key={t} className="text-right px-2 py-1.5 text-navy/80 font-sub">
                  {Math.round(rates[seg][t] * 100)}%
                </td>
              ))}
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );
}
