// --- Dev Office aspirational operating-revenue preset ---
//
// FY27 stays at the Finance-approved baseline ($4.66M). FY28/FY29 land on the
// Dev Office Pipeline Tool's outyear AOR projections ($6.25M / $6.35M). FY30
// plateaus at $6.5M, then drifts up 1%/yr. This is the aspiration, not the
// budget — AOR-bookable; P&L recognition can differ by ±$0.5M–$1M.
export const DEV_OFFICE_FY28_OPERATING_REVENUE = 6_250_000;
export const DEV_OFFICE_FY29_OPERATING_REVENUE = 6_350_000;
export const DEV_OFFICE_FY30_OPERATING_REVENUE = 6_500_000;
export const DEV_OFFICE_OUTYEAR_DRIFT_RATE = 0.01; // 1%/yr from FY30 base

export const DEV_OFFICE_ASPIRATIONAL_OPERATING_REVENUE: number[] = (() => {
  const arr: number[] = new Array(PROJECTION_LENGTH);
  arr[0] = FY27_OPERATING_REVENUE; // FY27 — Finance-approved, unchanged
  arr[1] = DEV_OFFICE_FY28_OPERATING_REVENUE;
  arr[2] = DEV_OFFICE_FY29_OPERATING_REVENUE;
  for (let i = 3; i < PROJECTION_LENGTH; i++) {
    arr[i] = Math.round(
      DEV_OFFICE_FY30_OPERATING_REVENUE *
        Math.pow(1 + DEV_OFFICE_OUTYEAR_DRIFT_RATE, i - 3)
    );
  }
  return arr;
})();

export function isDevOfficeAspirationActive(operatingRevenue: number[]): boolean {
  if (operatingRevenue.length !== DEV_OFFICE_ASPIRATIONAL_OPERATING_REVENUE.length) {
    return false;
  }
  return operatingRevenue.every(
    (v, i) => v === DEV_OFFICE_ASPIRATIONAL_OPERATING_REVENUE[i]
  );
}

// --- Formatting helpers ---

export function formatDollars(n: number): string {
  return new Intl.NumberFormat('en-US', {
    style: 'currency',
    currency: 'USD',
    maximumFractionDigits: 0,
  }).format(n);
}

export function formatMillions(n: number, fractionDigits = 1): string {
  const m = n / 1_000_000;
  const sign = m < 0 ? '-' : '';
  return `${sign}$${Math.abs(m).toFixed(fractionDigits)}M`;
}

export function formatPercent(n: number, fractionDigits = 1): string {
  return `${(n * 100).toFixed(fractionDigits)}%`;
}
